#include <stdio.h>
#include <stdlib.h>

int main() {
    int n;
    int zbir = 0;

    printf("Koliko brojeva zelite unijeti: ");
    scanf("%d", &n);

    for (int i = 0; i < n; i++) {
        int *x = (int *)malloc(sizeof(int));

        if (x == NULL) {
            printf("Alokacija nije uspjela.\n");
            return 1;
        }

        printf("Unesite broj %d: ", i + 1);
        scanf("%d", x);

        zbir += *x;

        free(x);
    }

    printf("Zbir unesenih brojeva je: %d\n", zbir);

    return 0;
}
